import{_ as t,o as s,c as r,a2 as i}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Audience & Score","description":"","frontmatter":{"title":"Audience & Score"},"headers":[],"relativePath":"docs/fr/publishers/audience-setup.md","filePath":"docs/fr/publishers/audience-setup.md"}'),o={name:"docs/fr/publishers/audience-setup.md"};function n(a,e,u,l,c,d){return s(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="configuration-de-l-audience-score" tabindex="-1">Configuration de l&#39;Audience &amp; Score <a class="header-anchor" href="#configuration-de-l-audience-score" aria-label="Permalink to &quot;Configuration de l&#39;Audience &amp; Score&quot;">​</a></h1><p>Votre fiche audience est votre vitrine auprès des annonceurs. Plus elle est précise, plus vous recevrez de propositions pertinentes.</p><h2 id="_1-l-identite-de-votre-audience" tabindex="-1">1. L&#39;Identité de votre Audience <a class="header-anchor" href="#_1-l-identite-de-votre-audience" aria-label="Permalink to &quot;1. L&#39;Identité de votre Audience&quot;">​</a></h2><p>C&#39;est la première chose que l&#39;annonceur voit. Soignez la présentation pour déclencher le &quot;coup de cœur&quot;.</p><ul><li><strong>Présentation :</strong> Racontez votre histoire, vos valeurs et votre positionnement.</li><li><strong>Engagements RSE :</strong> Cochez les cases (Made in France, Colis réutilisables...) uniquement si vous pouvez le prouver.</li><li><strong>Visuels :</strong> Uploadez un logo et une bannière qui représentent votre univers.</li></ul><div class="gi-accent-box"><strong>💡 Le conseil de l&#39;équipe</strong><p style="margin:0.5rem 0 0;">Dans le champ <strong>&quot;Persona&quot;</strong>, soyez descriptif : <em>&quot;Jardinier amateur ou expert cherchant des produits durables pour entretenir son potager.&quot;</em> Cela aide les annonceurs à mieux comprendre qui sont vos clients.</p></div><h2 id="_2-les-donnees-demographiques-data" tabindex="-1">2. Les Données Démographiques (Data) <a class="header-anchor" href="#_2-les-donnees-demographiques-data" aria-label="Permalink to &quot;2. Les Données Démographiques (Data)&quot;">​</a></h2><p>Ces champs alimentent l&#39;algorithme de getinside pour le matching.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>Panier Moyen</strong><p>Indiquez le montant HT moyen. Cela permet aux annonceurs de cibler par pouvoir d&#39;achat.</p></div><div class="gi-value-card"><strong>Typologie (B2C/B2B)</strong><p>Critère excluant. Assurez-vous qu&#39;il est correct.</p></div><div class="gi-value-card"><strong>Profil d&#39;acheteur</strong><p><em>Discounter, Économe, Médian, Élevé.</em> Positionnez-vous par rapport à votre marché.</p></div></div><h2 id="_3-activez-les-formats-pour-cette-audience" tabindex="-1">3. Activez les formats pour cette audience <a class="header-anchor" href="#_3-activez-les-formats-pour-cette-audience" aria-label="Permalink to &quot;3. Activez les formats pour cette audience&quot;">​</a></h2><p>Pour chaque audience créée, activez indépendamment les formats que vous souhaitez monétiser :</p><ul><li><strong>📦 Insertion Colis</strong> — Flyers ou échantillons dans vos colis</li><li><strong>📧 Emailing Dédié</strong> — Recommandation via votre newsletter</li><li><strong>📩 Display Email</strong> — Bannières dans vos emails</li><li><strong>📱 Social Ads</strong> — Publications sponsorisées Instagram / TikTok</li><li><strong>🎁 Jeu Concours</strong> — Mécanique de collecte de leads</li></ul><blockquote><p>Vous pouvez activer ou désactiver un format à tout moment sans impact sur les campagnes en cours.</p></blockquote><h2 id="_4-gerer-plusieurs-audiences-et-sites" tabindex="-1">4. Gérer plusieurs audiences et sites <a class="header-anchor" href="#_4-gerer-plusieurs-audiences-et-sites" aria-label="Permalink to &quot;4. Gérer plusieurs audiences et sites&quot;">​</a></h2><p><strong>Un seul compte suffit</strong>, même si vous opérez plusieurs sites e-commerce. Chaque site peut avoir sa propre fiche audience avec ses données spécifiques.</p><p><strong>Espace :</strong> Monétisation → Catalogue → + Nouvelle audience</p><p>Bonnes pratiques pour un catalogue multi-audiences :</p><ul><li>Nommez clairement chaque audience (ex: &quot;Site Mode Femme&quot;, &quot;Site Jardin B2C&quot;)</li><li>Renseignez des données distinctes par site — ne mutualisez pas les chiffres</li><li>Activez uniquement les formats que vous pouvez réellement honorer sur ce site</li></ul><p><strong>International :</strong> getinside opère dans toute l&#39;Europe. Ajoutez vos audiences européennes pour recevoir des campagnes ciblées par pays.</p><h2 id="_5-votre-score-distributeur" tabindex="-1">5. Votre Score Distributeur <a class="header-anchor" href="#_5-votre-score-distributeur" aria-label="Permalink to &quot;5. Votre Score Distributeur&quot;">​</a></h2><p>Votre fiche audience est directement liée à votre Score Distributeur — la note sur 5 étoiles qui détermine votre visibilité auprès des annonceurs.</p><table tabindex="0"><thead><tr><th>Score</th><th>Visibilité</th></tr></thead><tbody><tr><td>&lt; 3/5</td><td>Audience peu visible — action requise</td></tr><tr><td>3–4/5</td><td>Standard — propositions régulières</td></tr><tr><td>&gt; 4/5</td><td>🏆 Top Distributeur — priorité dans les résultats</td></tr></tbody></table><p>Une fiche audience bien remplie (persona détaillé, données précises, visuels soignés) améliore directement plusieurs des 7 critères de notation.</p><p>→ <a href="/handbook/docs/fr/publishers/score-distributor.html">Guide complet : Score Distributeur</a></p><h2 id="questions-frequentes" tabindex="-1">Questions fréquentes <a class="header-anchor" href="#questions-frequentes" aria-label="Permalink to &quot;Questions fréquentes&quot;">​</a></h2><p><strong>Comment ajouter un utilisateur à mon compte ?</strong> Rendez-vous dans <strong>Mon Organisation → Équipe</strong> → <code>+ Ajouter un membre</code>. Recommandé : ayez toujours un backup pour assurer la réactivité sous 48h.</p><p><strong>Puis-je gérer plusieurs sites depuis un seul compte ?</strong> Oui. Un compte getinside peut héberger autant d&#39;audiences que vous le souhaitez — une par site ou par segment client.</p><p><strong>Où suivre mes filleuls (affiliation) ?</strong> Dans l&#39;onglet <strong>Affiliation</strong>. Vous touchez <strong>20% de commission récurrente</strong> sur les frais de plateforme de vos filleuls, versés directement dans votre Wallet. Les filleuls doivent être établis en France ou dans l&#39;EEE.</p><p><strong>Mon Score Distributeur a baissé — pourquoi ?</strong> Le score est recalculé dynamiquement. Causes fréquentes : réponse &gt; 48h, refus répétés sans contre-proposition, volumes distribués inférieurs aux engagements, CPM jugé trop élevé vs la concurrence. → Consultez le <a href="/handbook/docs/fr/publishers/score-distributor.html">guide Score Distributeur</a> pour le détail critère par critère.</p>',29)])])}const g=t(o,[["render",n]]);export{m as __pageData,g as default};
